import datetimeimport uuidfrom typing import Optionalfrom sqlalchemy import BIGINT, UUID, TIMESTAMP, INTEGER, Datefrom sqlalchemy.orm import Mapped, mapped_columnfrom database.entity.BaseModel import BaseModelclass PlatformUserStatModel(BaseModel):    __tablename__ = 'platform_user_stat'    id: Mapped[int] = mapped_column(INTEGER,  primary_key=True, autoincrement=True)    user_id: Mapped[uuid.UUID] = mapped_column(UUID)    login_count_7days: Mapped[Optional[int]] = mapped_column(INTEGER, comment="""7天内登录的次数""")    browse_count: Mapped[Optional[int]] = mapped_column(INTEGER, comment="""浏览数""")    message_count: Mapped[Optional[int]] = mapped_column(INTEGER, comment="""消息数""")    last_active_time: Mapped[Optional[datetime.datetime]] = mapped_column(TIMESTAMP, comment="""用户最后活跃时间""")    daily_duration: Mapped[Optional[int]] = mapped_column(INTEGER, comment="""日总时长""")    update_at: Mapped[Optional[datetime.datetime]] = mapped_column(TIMESTAMP, default=datetime.datetime.now())    create_at: Mapped[datetime.date] = mapped_column(Date, default=datetime.datetime.now().date())